-- Flashlight
local flashlightLight = nil
local function setupFlashlight()
    local character = LocalPlayer.Character
    if not character then return end
    
    local root = character:FindFirstChild("HumanoidRootPart")
    if not root then return end
    
    if States.Flashlight then
        if not flashlightLight or not flashlightLight.Parent then
            flashlightLight = Instance.new("PointLight")
            flashlightLight.Brightness = 2.5
            flashlightLight.Range = 999999
        end
        flashlightLight.Parent = root
        flashlightLight.Enabled = true
    else
        if flashlightLight then
            flashlightLight.Enabled = false
        end
    end
end

-- Speed Lock
local speedConnection
local function setupSpeedLock()
    if speedConnection then
        speedConnection:Disconnect()
        speedConnection = nil
    end
    
    if States.SpeedLock then
        speedConnection = RunService.Heartbeat:Connect(function()
            local character = LocalPlayer.Character
            if character then
                local humanoid = character:FindFirstChildOfClass("Humanoid")
                if humanoid then
                    humanoid.WalkSpeed = States.LockedSpeed
                end
            end
        end)
    end
end

-- Create Window
local Window = Rayfield:CreateWindow({
    Name = "AbyssX Hub",
    LoadingTitle = "AbyssX Hub",
    LoadingSubtitle = "Flee the Facility Edition",
    ConfigurationSaving = {
        Enabled = true,
        FolderName = "AbyssXHub",
        FileName = "FTFConfig"
    },
    Discord = {
        Enabled = false,
        Invite = "",
        RememberJoins = false
    },
    KeySystem = false
})

-- ESP Tab
local ESPTab = Window:CreateTab("ESP", 4483362458)

ESPTab:CreateSection("Player ESP")

ESPTab:CreateToggle({
    Name = "Player ESP",
    CurrentValue = false,
    Flag = "PlayerESP",
    Callback = function(Value)
        States.PlayerESP = Value
        if Value then
            updatePlayerESP()
        else
            for name, _ in pairs(Highlights) do
                if name:sub(1, 7) == "Player_" then
                    removeHighlight(name)
                end
            end
        end
    end
})

ESPTab:CreateSection("Object ESP")

ESPTab:CreateToggle({
    Name = "PC ESP",
    CurrentValue = false,
    Flag = "PCESP",
    Callback = function(Value)
        States.PCESP = Value
        if Value then
            setupPCESP()
            Rayfield:Notify({
                Title = "PC ESP",
                Content = "PC ESP Enabled! Scanning for computers...",
                Duration = 3,
                Image = 4483362458
            })
        else
            -- Cleanup PC ESP
            for name, _ in pairs(Highlights) do
                if name:sub(1, 3) == "PC_" then
                    removeHighlight(name)
                end
            end
            for id, _ in pairs(PCObjects) do
                if ConnectionCleanups[id] then
                    ConnectionCleanups[id]:Disconnect()
                    ConnectionCleanups[id] = nil
                end
            end
            PCObjects = {}
        end
    end
})

ESPTab:CreateToggle({
    Name = "Pods ESP",
    CurrentValue = false,
    Flag = "PodsESP",
    Callback = function(Value)
        States.PodsESP = Value
        if Value then
            updatePodsESP()
        else
            for name, _ in pairs(Highlights) do
                if name:sub(1, 4) == "Pod_" then
                    removeHighlight(name)
                end
            end
        end
    end
})

ESPTab:CreateToggle({
    Name = "Exits ESP",
    CurrentValue = false,
    Flag = "ExitsESP",
    Callback = function(Value)
        States.ExitsESP = Value
        if Value then
            updateExitsESP()
        else
            for name, _ in pairs(Highlights) do
                if name:sub(1, 5) == "Exit_" then
                    removeHighlight(name)
                end
            end
        end
    end
})

ESPTab:CreateButton({
    Name = "Refresh ESP",
    Callback = function()
        refreshESP()
        Rayfield:Notify({
            Title = "ESP Refreshed",
            Content = "All ESP markers have been refreshed!",
            Duration = 3,
            Image = 4483362458
        })
    end
})

