        States.SpeedLock = false
        if speedConnection then
            speedConnection:Disconnect()
            speedConnection = nil
        end
        local character = LocalPlayer.Character
        if character then
            local humanoid = character:FindFirstChildOfClass("Humanoid")
            if humanoid then
                humanoid.WalkSpeed = 16
            end
