-- Game State Monitoring
local isGameActive = ReplicatedStorage:WaitForChild("IsGameActive", 5)
local gameStatus = ReplicatedStorage:WaitForChild("GameStatus", 5)

if isGameActive then
    isGameActive.Changed:Connect(function()
        task.wait(0.5)
        if States.PCESP then
            setupPCESP()
        end
        refreshESP()
    end)
end

if gameStatus then
    gameStatus.Changed:Connect(function()
        task.wait(0.5)
        if States.PCESP then
            setupPCESP()
        end
        refreshESP()
    end)
end

-- Player monitoring
Players.PlayerAdded:Connect(function(player)
    if States.PlayerESP then
        task.wait(1)
        updatePlayerESP()
    end
end)

Players.PlayerRemoving:Connect(function(player)
    removeHighlight("Player_" .. player.Name)
end)

-- Character handling
LocalPlayer.CharacterAdded:Connect(function(char)
    task.wait(0.5)
    if States.Flashlight then
        setupFlashlight()
    end
    if States.SpeedLock then
        setupSpeedLock()
    end
end)

